mutation RegisterUser($input: RegisterUserDto!) {
  registerUser(registerUserDto: $input)
}

mutation LoginUser($input: LoginUserDto!) {
  loginUser(loginUserDto: $input) {
    accessToken
    idToken
    refreshToken
  }
}

