query Propositions($skip: Int!, $take: Int!) {
  propositions(skip: $skip, take: $take) {
    items {
      id
      externalId
      title
      status
      summary
    }
    total
    hasMore
  }
}

query Representatives($skip: Int!, $take: Int!, $chamber: String) {
  representatives(skip: $skip, take: $take, chamber: $chamber) {
    items {
      id
      name
      party
      chamber
      district
    }
    total
    hasMore
  }
}

